parameters.content:
// Inicialisasi config — reemplazar con valores reales
$input.first().json = {
  config: {
    KPSULA_HOST: "https://pokepok.kpsula.app",
    KPSULA_API_KEY: "TU_API_KEY_AQUI",
    KPSULA_WEBHOOK_SECRET: "TU_SECRET_AQUI",
    TELEGRAM_BOT_TOKEN: "TU_BOT_TOKEN_AQUI",
    OPENAI_API_KEY: "TU_OPENAI_KEY_AQUI"
  }
};
return $input.first();

// Parse Telegram message
const msg = $input.first().json.message;
const chatId = msg.chat.id;
const userId = msg.from.id;
const userName = msg.from.first_name;
const isPhoto = !!msg.photo && msg.photo.length > 0;
const isText = !!msg.text;
const messageText = msg.text || null;
const photoId = isPhoto ? msg.photo[msg.photo.length - 1].file_id : null;
const caption = msg.caption || null;

return {
  chatId,
  userId,
  userName,
  isPhoto,
  isText,
  messageText,
  photoId,
  caption,
  config: $input.first().json.config
};

// Cargar orden_id de sesión (si existe)
const sessionKey = `session_${$node["Parse Telegram Message"].json.chatId}`;
const workflowData = await $getWorkflowData(sessionKey);
const ordenId = workflowData ? workflowData.orden_id : null;

return {
  ...Object.fromEntries(Object.entries($input.first().json).map(([k, v]) => [k, v])),
  ordenId: ordenId,
  sessionKey: sessionKey
};

// Parsear respuesta del agent para extraer datos de la orden
const resp = $node["AI Agent (OpenAI)"].json.response;

// Buscar patrón: dirección, teléfono, nombre, items
const dirMatch = resp.match(/(dirección|dirección|address):\s*([^\n]+)/i);
const telMatch = resp.match(/(teléfono|telefono|phone):\s*([^\n]+)/i);
const nomMatch = resp.match(/(nombre|name):\s*([^\n]+)/i);
const itemsMatch = resp.match(/(items?|productos?|comida):\s*([^\n]+)/is);

// Construcción básica de payload
const payload = {
  direccion: dirMatch ? dirMatch[2].trim() : "dirección no especificada",
  telefono: telMatch ? telMatch[2].trim() : "0000",
  nombre_cliente: nomMatch ? nomMatch[2].trim() : "cliente",
  items: itemsMatch ? itemsMatch[2].trim() : "items no especificados",
  config: $input.first().json.config,
  chatId: $node["Parse Telegram Message"].json.chatId
};

return payload;

parameters.url:
: "POST",
        "headerParameters": {
          "parameters": [
            {
              "name": "X-API-Key",
              "value": "{{ $node[\"extract-order-data\"].json.config.KPSULA_API_KEY }}"
            },
            {
              "name": "Content-Type",
              "value": "application/json"
            }
          ]
        },
        "body": "{{ JSON.stringify({\n  channel: 'telegram',\n  chatId: $node[\"extract-order-data\"].json.chatId.toString(),\n  nombre_cliente: $node[\"extract-order-data\"].json.nombre_cliente,\n  telefono: $node[\"extract-order-data\"].json.telefono,\n  direccion: $node[\"extract-order-data\"].json.direccion,\n  items: $node[\"extract-order-data\"].json.items,\n  sede_id: null\n}) }}"
      },

: "// Guardar orden_id en sesión para Workflow 2
const ordenId = $node[\"POST /ordenes (crear)\"].json.orden.id;
const correlativo = $node[\"POST /ordenes (crear)\"].json.orden.correlativo;
const sessionKey = $node[\"load-session\"].json.sessionKey;

await $setWorkflowData(sessionKey, { orden_id: ordenId, correlativo: correlativo });

return {
  ordenId: ordenId,
  correlativo: correlativo,
  config: $input.first().json.config,
  chatId: $node[\"Parse Telegram Message\"].json.chatId
};",
        "language": "javaScript"
      },
      "id": "save-session",
      "name": "Guardar orden_id en sesión",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1900, 100]
    },
    {
      "parameters": {
        "chatId": "{{ $node[\"save-session\"].json.chatId }}",
        "messageType": "text",
        "text": "✅ Orden creada!\n\n📋 Correlativo: {{$node[\"save-session\"].json.correlativo}}\n\nAhora envía una foto del comprobante de pago para validar tu orden."
      },
      "id": "respond-order-ok",
      "name": "Responder: Orden creada",
      "type": "n8n-nodes-base.telegram",
      "typeVersion": 1,
      "position": [2100, 100],
      "credentials": {
        "telegramApi": "telegram-bot-token"
      }
    },
    {
      "parameters": {
        "chatId": "{{ $node[\"Parse Telegram Message\"].json.chatId }}",
        "messageType": "text",
        "text": "{{ $node[\"AI Agent (OpenAI)\"].json.response }}"
      },
      "id": "respond-conversational",
      "name": "Responder: Conversacional",
      "type": "n8n-nodes-base.telegram",
      "typeVersion": 1,
      "position": [1500, 400],
      "credentials": {
        "telegramApi": "telegram-bot-token"
      }
    }
  ],
  "connections": {
    "telegram-trigger": {
      "main": [[{ "node": "set-config", "type": "main", "index": 0 }]]
    },
    "set-config": {
      "main": [[{ "node": "parse-telegram", "type": "main", "index": 0 }]]
    },
    "parse-telegram": {
      "main": [[{ "node": "is-text-message", "type": "main", "index": 0 }]]
    },
    "is-text-message": {
      "main": [
        [{ "node": "get-contexto", "type": "main", "index": 0 }],
        [{ "node": "respond-conversational", "type": "main", "index": 0 }]
      ]
    },
    "get-contexto": {
      "main": [[{ "node": "load-session", "type": "main", "index": 0 }]]
    },
    "load-session": {
      "main": [[{ "node": "ai-agent", "type": "main", "index": 0 }]]
    },
    "ai-agent": {
      "main": [[{ "node": "check-crear-orden", "type": "main", "index": 0 }]]
    },
    "check-crear-orden": {
      "main": [
        [{ "node": "extract-order-data", "type": "main", "index": 0 }],
        [{ "node": "respond-conversational", "type": "main", "index": 0 }]
      ]
    },
    "extract-order-data": {
      "main": [[{ "node": "post-create-orden", "type": "main", "index": 0 }]]
    },
    "post-create-orden": {
      "main": [[{ "node": "save-session", "type": "main", "index": 0 }]]
    },
    "save-session": {
      "main": [[{ "node": "respond-order-ok", "type": "main", "index": 0 }]]
    }
  }
}
